import json

import yaml

from prompty.model import TextPart


def test_load_json_textpart():
    json_data = r"""
    {
      "value": "Hello, world!"
    }
    """
    data = json.loads(json_data, strict=False)
    instance = TextPart.load(data)
    assert instance is not None
    assert instance.value == "Hello, world!"


def test_load_yaml_textpart():
    yaml_data = r"""
    value: Hello, world!

    """
    data = yaml.load(yaml_data, Loader=yaml.FullLoader)
    instance = TextPart.load(data)
    assert instance is not None
    assert instance.value == "Hello, world!"


def test_roundtrip_json_textpart():
    """Test that load -> save -> load produces equivalent data."""
    json_data = r"""
    {
      "value": "Hello, world!"
    }
    """
    original_data = json.loads(json_data, strict=False)
    instance = TextPart.load(original_data)
    saved_data = instance.save()
    reloaded = TextPart.load(saved_data)
    assert reloaded is not None
    assert reloaded.value == "Hello, world!"


def test_to_json_textpart():
    """Test that to_json produces valid JSON."""
    json_data = r"""
    {
      "value": "Hello, world!"
    }
    """
    data = json.loads(json_data, strict=False)
    instance = TextPart.load(data)
    json_output = instance.to_json()
    assert json_output is not None
    parsed = json.loads(json_output)
    assert isinstance(parsed, dict)


def test_to_yaml_textpart():
    """Test that to_yaml produces valid YAML."""
    json_data = r"""
    {
      "value": "Hello, world!"
    }
    """
    data = json.loads(json_data, strict=False)
    instance = TextPart.load(data)
    yaml_output = instance.to_yaml()
    assert yaml_output is not None
    parsed = yaml.safe_load(yaml_output)
    assert isinstance(parsed, dict)
